// Obtener datos del repositorio
const repo = $input.first().json;

// Calcular horas esperadas
function calcularHorasDetalladas(inicio, fin, horasDia, horasViernes) {
  let totalHoras = 0;
  let diasLaborables = 0;
  const start = new Date(inicio + 'T00:00:00');
  const end = new Date(fin + 'T23:59:59');

  for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
    const diaSemana = d.getDay();

    if (diaSemana >= 1 && diaSemana <= 4) {
      totalHoras += horasDia;
      diasLaborables++;
    } 
    else if (diaSemana === 5) {
      totalHoras += horasViernes;
      diasLaborables++;
    }
  }

  return { totalHoras, diasLaborables };
}

const calculo = calcularHorasDetalladas(
  repo.fechaInicio,
  repo.fechaFin,
  repo.horasLunesJueves,
  repo.horasViernes
);

// Retornar array de personas
return repo.personas.map(id => ({
  personId: id,
  fechaInicio: repo.fechaInicio,
  fechaFin: repo.fechaFin,
  diasLaborables: calculo.diasLaborables,
  horasEsperadas: calculo.totalHoras
}));

// 1. FUNCIONES AUXILIARES
function decodeHTMLEntities(text) {
  const entities = {
    '&aacute;': 'á', '&eacute;': 'é', '&iacute;': 'í', '&oacute;': 'ó', '&uacute;': 'ú',
    '&Aacute;': 'Á', '&Eacute;': 'É', '&Iacute;': 'Í', '&Oacute;': 'Ó', '&Uacute;': 'Ú',
    '&ntilde;': 'ñ', '&Ntilde;': 'Ñ',
    '&uuml;': 'ü', '&Uuml;': 'Ü',
    '&amp;': '&', '&lt;': '<', '&gt;': '>', '&quot;': '"', '&#39;': "'"
  };
  return text.replace(/&[a-zA-Z0-9#]+;/g, (match) => entities[match] || match);
}

function calcularHorasDetalladas(inicio, fin) {
  let totalHoras = 0;
  let diasLaborables = 0;
  // Aseguramos que las fechas se interpreten correctamente sin problemas de zona horaria al crear el objeto
  const start = new Date(inicio + 'T00:00:00');
  const end = new Date(fin + 'T23:59:59');

  for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
    const diaSemana = d.getDay();
    if (diaSemana >= 1 && diaSemana <= 4) { // Lunes a Jueves
      totalHoras += 8;
      diasLaborables++;
    } 
    else if (diaSemana === 5) { // Viernes
      totalHoras += 6.5;
      diasLaborables++;
    }
  }
  return { totalHoras, diasLaborables };
}

// 2. CONFIGURACIÓN DE FECHAS
const hoy = new Date();
const offsetChile = -3 * 60; // GMT-3
const offsetLocal = hoy.getTimezoneOffset();

// Ajustar a hora Chile
hoy.setMinutes(hoy.getMinutes() + (offsetLocal - offsetChile));

// Restar 1 día
hoy.setDate(hoy.getDate() - 1); 

// Definir inicio y fin del periodo
const fechaInicio = `${hoy.getFullYear()}-${String(hoy.getMonth() + 1).padStart(2, '0')}-01`;
const fechaFin = `${hoy.getFullYear()}-${String(hoy.getMonth() + 1).padStart(2, '0')}-${String(hoy.getDate()).padStart(2, '0')}`;

// Calcular las horas ideales para este rango de fechas
const calculoBase = calcularHorasDetalladas(fechaInicio, fechaFin);

// 3. PROCESAR CADA PERSONA
const resultados = [];

for (const item of $input.all()) {
  const registroAPI = item.json;
  const registros = registroAPI.time || [];

  const personId = registroAPI.personid || (registros.length > 0 ? registros[0].personid : 'Desconocido');

  let nombreCompleto = 'Sin registros';
  if (registros.length > 0) {
    const nombreRaw = registros[0].person || `ID: ${personId}`;
    nombreCompleto = decodeHTMLEntities(nombreRaw);
  }

  // Sumar horas reportadas
  let horasIngresadas = 0;
  for (const registro of registros) {
    horasIngresadas += parseFloat(registro.time || 0);
  }

  const horasEsperadas = calculoBase.totalHoras;

  // REQ 5 y 7: Cálculo de Diferencia
  // Lógica: Esperadas - Ingresadas
  // Positivo = Debes horas (Falta ingresar)
  // Negativo = Tienes horas a favor (Extra)
  const diferenciaReal = horasEsperadas - horasIngresadas;

  // Math.abs para no ver negativos falsos.
  const diferenciaVisual = parseFloat(Math.abs(diferenciaReal).toFixed(2));

  const porcentaje = horasEsperadas > 0 ? (horasIngresadas / horasEsperadas) * 100 : 0;

  // Determinar Estado
  let estado;
  if (porcentaje >= 100) {
    estado = '✅ Al día';
  } else if (porcentaje >= 80) {
    estado = '⚠️ Advertencia';
  } else {
    estado = '❌ Atrasado';
  }

  resultados.push({
    ID: personId,
    Nombre: nombreCompleto,
    diasLaborables: calculoBase.diasLaborables,
    horasEsperadas: parseFloat(horasEsperadas.toFixed(2)),
    horasIngresadas: parseFloat(horasIngresadas.toFixed(2)),
    diferencia: diferenciaVisual, // REQ 7
    porcentaje: parseFloat(porcentaje.toFixed(2)),
    estado: estado,
    cantidadRegistros: registros.length,
    periodoInicio: fechaInicio, 
    periodoFin: fechaFin
  });
}

return resultados;

